import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom"; // Para redirigir a NewGamePage
import "../styles/mainmenu/LeagueMenu.css";

function LeagueMenu() {
    const navigate = useNavigate(); // Hook para redirigir
    const [jornadas, setJornadas] = useState([]);
    const [clasificacion, setClasificacion] = useState([]);
    const [jornadaActual, setJornadaActual] = useState(0);
    const [modalVisible, setModalVisible] = useState(false);
    const [modalType, setModalType] = useState(""); // "jornada" o "clasificacion"
    const [equiposSeleccionados, setEquiposSeleccionados] = useState([]);

    useEffect(() => {
        const equipos = JSON.parse(localStorage.getItem("equipos")) || [];
        const seleccionados = equipos.filter((equipo) => equipo.player);
        setEquiposSeleccionados(seleccionados);

        const calendario = JSON.parse(localStorage.getItem("calendario")) || [];
        setJornadas(calendario);

        const clasificacionData = JSON.parse(localStorage.getItem("clasificacion")) || [];
        setClasificacion(clasificacionData);
    }, []);

    const iniciarPartido = (local, visitante) => {
        // Redirigir a NewGamePage con los datos de los equipos
        navigate("/new-game", { state: { local, visitante } });
    };

    const abrirModal = (type) => {
        setModalType(type);
        setModalVisible(true);
    };

    const cerrarModal = () => {
        setModalVisible(false);
    };

    const siguienteJornada = () => {
        if (jornadaActual < jornadas.length - 1) {
            setJornadaActual(jornadaActual + 1);
        }
    };

    const anteriorJornada = () => {
        if (jornadaActual > 0) {
            setJornadaActual(jornadaActual - 1);
        }
    };

    return (
        <div className="league-menu">
            <h1>League Menu</h1>

            {/* Navegación de Jornadas */}
            <div className="navegacion-jornadas">
                <button onClick={anteriorJornada} disabled={jornadaActual === 0}>
                    ⬅ Anterior
                </button>
                <button onClick={siguienteJornada} disabled={jornadaActual === jornadas.length - 1}>
                    Siguiente ➡
                </button>
            </div>

            {/* Preview del próximo partido del equipo seleccionado */}
            <div className="proximo-partido">
                <h2>Próximo Partido</h2>
                {jornadas[jornadaActual]?.map((partido, index) => {
                    const { local, visitante } = partido;
                    const esEquipoSeleccionado =
                        equiposSeleccionados.some((e) => e.id === local.id) ||
                        equiposSeleccionados.some((e) => e.id === visitante.id);

                    if (esEquipoSeleccionado) {
                        return (
                            <div key={index} className="partido-preview">
                                <div className="equipo">
                                    <img
                                        src={local.imagen || "/assets/images/default.png"}
                                        alt={local.nombre || "Equipo Local"}
                                        className="escudo"
                                    />
                                    <span>{local.nombre || "Equipo Local"}</span>
                                </div>
                                <span className="vs">vs</span>
                                <div className="equipo">
                                    <img
                                        src={visitante.imagen || "/assets/images/default.png"}
                                        alt={visitante.nombre || "Equipo Visitante"}
                                        className="escudo"
                                    />
                                    <span>{visitante.nombre || "Equipo Visitante"}</span>
                                </div>
                                <button onClick={() => iniciarPartido(local, visitante)}>
                                    Jugar Partido
                                </button>
                            </div>
                        );
                    }
                    return null;
                })}
            </div>

            {/* Preview de la Clasificación */}
            <div className="clasificacion-preview-container" onClick={() => abrirModal("clasificacion")}>
                <h2>Clasificación</h2>
                <div className="clasificacion-preview">
                    {clasificacion.slice(0, 5).map((equipo, index) => (
                        <div key={index} className="equipo-clasificacion-preview">
                            <span>{index + 1}.</span>
                            <img
                                src={equipo.imagen || "/assets/images/default.png"}
                                alt={equipo.nombre || "Equipo"}
                                className="escudo"
                            />
                            <span>{equipo.nombre || "Equipo"}</span>
                            <span>{equipo.puntos || 0} pts</span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Modal */}
            {modalVisible && (
                <div className="modal-overlay" onClick={cerrarModal}>
                    <div
                        className="modal-content"
                        onClick={(e) => e.stopPropagation()} // Evitar cerrar al hacer clic dentro del modal
                    >
                        {modalType === "clasificacion" && (
                            <>
                                <h2>Clasificación</h2>
                                <table className="clasificacion-detalle">
                                    <thead>
                                        <tr>
                                            <th>#</th>
                                            <th>Equipo</th>
                                            <th>PJ</th>
                                            <th>V</th>
                                            <th>E</th>
                                            <th>D</th>
                                            <th>GF</th>
                                            <th>GC</th>
                                            <th>DG</th>
                                            <th>Puntos</th>
                                            <th>Últimos 5</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {clasificacion.map((equipo, index) => (
                                            <tr
                                                key={equipo.id}
                                                className={index >= clasificacion.length - 3 ? "descenso" : ""}
                                            >
                                                <td>{index + 1}</td>
                                                <td className="equipo-nombre">
                                                    <img
                                                        src={equipo.imagen || "/assets/images/default.png"}
                                                        alt={equipo.nombre || "Equipo"}
                                                        className="escudo"
                                                    />
                                                    {equipo.nombre || "Equipo"}
                                                </td>
                                                <td>{equipo.partidosJugados || 0}</td>
                                                <td>{equipo.victorias || 0}</td>
                                                <td>{equipo.empates || 0}</td>
                                                <td>{equipo.derrotas || 0}</td>
                                                <td>{equipo.golesFavor || 0}</td>
                                                <td>{equipo.golesContra || 0}</td>
                                                <td>{equipo.diferenciaGoles || 0}</td>
                                                <td>{equipo.puntos || 0}</td>
                                                <td className="ultimos-resultados">
                                                    {equipo.ultimosResultados?.map((resultado, i) => (
                                                        <span
                                                            key={i}
                                                            className={`resultado ${
                                                                resultado === "W"
                                                                    ? "win"
                                                                    : resultado === "D"
                                                                    ? "draw"
                                                                    : "loss"
                                                            }`}
                                                        >
                                                            {resultado === "W" ? "✔" : resultado === "D" ? "⚪" : "❌"}
                                                        </span>
                                                    )) || "N/A"}
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

export default LeagueMenu;
